import { defineConfig, memoryCache } from "@hushkey/howl/api";

/** Per-request state shared across middleware and handlers. */
export interface State {
  title: string;
  userContext?: { id: string; roles: Role[] };
}

export const roles = ["USER", "ADMIN"] as const;
export type Role = typeof roles[number];

export const { defineApi, config: apiConfig } = defineConfig<State, Role>({
  roles,
  cache: memoryCache({ maxSize: 500 }),
  defaultRateLimit: { max: 100, windowMs: 60_000 },
  getRateLimitIdentifier: (ctx) => ctx.state.userContext?.id,
  checkPermissionStrategy: (ctx, allowedRoles) => {
    const user = ctx.state.userContext;
    if (!user) return ctx.json({ error: "Unauthorized" }, { status: 401 });
    if (!allowedRoles.some((r) => user.roles.includes(r))) {
      return ctx.json({ error: "Forbidden" }, { status: 403 });
    }
  },
});

import { Howl, staticFiles } from "@hushkey/howl";
import { compression, coalesceRequests } from "@hushkey/howl/middleware";
import { vueEngine } from "@hushkey/howl-vue";
import { apiConfig, type State } from "../howl.config.ts";

export const app = new Howl<State>({
  logger: true,            // timestamped, PID-tagged console output
  engines: { vue: vueEngine() },
});

app.use(coalesceRequests());
app.use(compression());
app.use(staticFiles());

app.use((ctx) => {
  ctx.state.title = "my-app";
  return ctx.next();
});

app.fsApiRoutes(apiConfig);   // crawl apis/**/*.api.ts
app.fsClientRoutes();         // crawl pages/**

export default { app };

import { HowlBuilder } from "@hushkey/howl/dev";
import { vuePlugin } from "@hushkey/howl-vue/plugin";
import { httpClientGenPlugin, tailwindPlugin } from "@hushkey/howl/plugins";
import { app } from "./server/main.ts";
import type { State } from "./howl.config.ts";

const builder = new HowlBuilder<State>(app, {
  root: import.meta.dirname ?? "",
  importApp: () => app,
  outDir: "dist",
  serverEntry: "./server/main.ts",   // apis/ resolved relative to this
  clientEntry: "./client/pages/_app.vue",
  plugins: [
    vuePlugin(),                      // owns .vue files
    httpClientGenPlugin({
      apiDir: "server/apis",
      outputFile: "./generated/http-client.ts",
      aliases: { "@server/": "server/" },
    }),
  ],
});

// Tailwind attaches to a specific builder instance.
tailwindPlugin(builder.getBuilder("default")!);

if (Deno.args.includes("build")) {
  await builder.build();
} else {
  await builder.listen({ port: 8000 });
}
